function extractTokenUsage(response, node, model, provider, inputPricePerM, outputPricePerM) {
  let inputTokens = 0, outputTokens = 0;
  if (provider === 'google') {
    inputTokens = response.usageMetadata?.promptTokenCount || 0;
    outputTokens = response.usageMetadata?.candidatesTokenCount || 0;
  } else if (provider === 'anthropic') {
    inputTokens = response.usage?.input_tokens || 0;
    outputTokens = response.usage?.output_tokens || 0;
  } else {
    inputTokens = response.usage?.prompt_tokens || 0;
    outputTokens = response.usage?.completion_tokens || 0;
  }
  const costUSD = (inputTokens * inputPricePerM / 1000000) + (outputTokens * outputPricePerM / 1000000);
  return { node, model, provider, inputTokens, outputTokens, costUSD: Math.round(costUSD * 1000000) / 1000000 };
}

// Aggregate planning outputs from all LLMs
const plotData = $('ChatGPT: Plot Outline').item.json;
const characterData = $('Claude: Character Development').item.json;
const researchData = $('Perplexity: Research & Facts').item.json;
const projectState = $('Initialize Project State').item.json;

// Extract token usage (updated model pricing)
const tokenUsage = [
  extractTokenUsage(plotData, 'ChatGPT: Plot Outline', 'gpt-4o', 'openai', 2.5, 10),
  extractTokenUsage(characterData, 'Claude: Character Development', 'claude-opus-4-6', 'anthropic', 15, 75),
  extractTokenUsage(researchData, 'Perplexity: Research & Facts', 'sonar-pro', 'perplexity', 3, 15)
];

// Parse responses
let plotOutline = {};
let characters = {};
let research = {};

try {
  if (plotData.choices && plotData.choices[0]) {
    const content = plotData.choices[0].message.content;
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    plotOutline = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: content };
  }
} catch (e) {
  plotOutline = { raw: plotData.choices?.[0]?.message?.content || 'Parse error' };
}

try {
  if (characterData.content && characterData.content[0]) {
    const content = characterData.content[0].text;
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    characters = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: content };
  }
} catch (e) {
  characters = { raw: characterData.content?.[0]?.text || 'Parse error' };
}

try {
  if (researchData.choices && researchData.choices[0]) {
    research = { content: researchData.choices[0].message.content };
  }
} catch (e) {
  research = { raw: 'Research parse error' };
}

// Pipeline logging
const pipelineLog = [{
  timestamp: new Date().toISOString(),
  node: 'Aggregate Planning Data',
  action: 'Planning phase complete',
  plotLength: JSON.stringify(plotOutline).length,
  characterCount: Object.keys(characters).length,
  researchLength: JSON.stringify(research).length,
  tokens: tokenUsage.reduce((sum, t) => sum + t.inputTokens + t.outputTokens, 0)
}];

return {
  json: {
    ...projectState,
    status: 'planning_complete',
    tokenUsage,
    pipelineLog,
    spareText: [],
    planning: {
      plotOutline,
      characters,
      research,
      completedAt: new Date().toISOString()
    }
  }
};

