// Combine chapter draft with creative suggestions
const projectState = $('Start Drafting Phase').item.json;
const claudeDraft = $('Claude: Write Chapter Draft').item.json;
const grokSuggestions = $('Grok: Creative Enhancements').item.json;

// Token usage (updated pricing)
const newTokens = [
  extractTokenUsage(claudeDraft, 'Claude: Write Chapter Draft', 'claude-opus-4-6', 'anthropic', 15, 75),
  extractTokenUsage(grokSuggestions, 'Grok: Creative Enhancements', 'grok-3', 'xai', 2, 10)
];
const tokenUsage = [...(projectState.tokenUsage || []), ...newTokens];

let chapterText = '';
let suggestions = [];

if (claudeDraft.content && claudeDraft.content[0]) {
  chapterText = claudeDraft.content[0].text;
}

try {
  if (grokSuggestions.choices && grokSuggestions.choices[0]) {
    const content = grokSuggestions.choices[0].message.content;
    const jsonMatch = content.match(/\[[\s\S]*\]/);
    suggestions = jsonMatch ? JSON.parse(jsonMatch[0]) : [];
  }
} catch (e) {
  suggestions = [{ note: 'Could not parse Grok suggestions' }];
}

// Capture Grok suggestions as spare text for potential reuse
const spareText = [...(projectState.spareText || [])];
if (suggestions.length > 0) {
  spareText.push({
    source: 'Grok: Creative Enhancements',
    chapter: parseInt(projectState.currentChapter),
    type: 'creative_suggestions',
    content: JSON.stringify(suggestions, null, 2)
  });
}

// Logging
const log = [...(projectState.pipelineLog || [])];
log.push({
  timestamp: new Date().toISOString(),
  node: 'Combine Draft & Suggestions',
  chapter: parseInt(projectState.currentChapter),
  action: 'Draft combined with suggestions',
  draftWords: chapterText.split(/\s+/).length,
  suggestionsCount: suggestions.length,
  tokens: newTokens.reduce((sum, t) => sum + t.inputTokens + t.outputTokens, 0)
});

return {
  json: {
    ...projectState,
    tokenUsage,
    pipelineLog: log,
    spareText,
    currentChapterDraft: {
      chapterNumber: parseInt(projectState.currentChapter),
      text: chapterText,
      wordCount: chapterText.split(/\s+/).length,
      creativeSuggestions: suggestions,
      draftedAt: new Date().toISOString()
    }
  }
};

function extractTokenUsage(response, node, model, provider, inputPricePerM, outputPricePerM) {
  let inputTokens = 0, outputTokens = 0;
  if (provider === 'google') {
    inputTokens = response.usageMetadata?.promptTokenCount || 0;
    outputTokens = response.usageMetadata?.candidatesTokenCount || 0;
  } else if (provider === 'anthropic') {
