  return { node, model, provider, inputTokens, outputTokens, costUSD: Math.round(costUSD * 1000000) / 1000000 };
}

// Aggregate all review feedback
const projectState = $('Combine Draft & Suggestions').item.json;
const geminiReview = $('Gemini: Comprehensive Review').item.json;
const chatgptConsistency = $('ChatGPT: Consistency Check').item.json;
const claudeLineEdit = $('Claude: Line Editing').item.json;

// Token usage (updated pricing)
const newTokens = [
  extractTokenUsage(geminiReview, 'Gemini: Comprehensive Review', 'gemini-2.5-flash', 'google', 0.15, 0.6),
  extractTokenUsage(chatgptConsistency, 'ChatGPT: Consistency Check', 'gpt-4o', 'openai', 2.5, 10),
  extractTokenUsage(claudeLineEdit, 'Claude: Line Editing', 'claude-sonnet-4-20250514', 'anthropic', 3, 15)
];
const tokenUsage = [...(projectState.tokenUsage || []), ...newTokens];

let developmentalFeedback = {};
let consistencyFeedback = {};
let lineEditFeedback = {};

try {
  if (geminiReview.candidates && geminiReview.candidates[0]) {
    const text = geminiReview.candidates[0].content.parts[0].text;
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    developmentalFeedback = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: text };
  }
} catch (e) {
  developmentalFeedback = { error: 'Parse error', raw: geminiReview };
}

try {
  if (chatgptConsistency.choices && chatgptConsistency.choices[0]) {
    const text = chatgptConsistency.choices[0].message.content;
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    consistencyFeedback = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: text };
  }
} catch (e) {
  consistencyFeedback = { error: 'Parse error' };
}

try {
  if (claudeLineEdit.content && claudeLineEdit.content[0]) {
    const text = claudeLineEdit.content[0].text;
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    lineEditFeedback = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: text };
  }
} catch (e) {
  lineEditFeedback = { error: 'Parse error' };
}

const scores = [
  developmentalFeedback.overallScore,
  consistencyFeedback.consistencyScore,
  lineEditFeedback.overallProseScore
].filter(s => typeof s === 'number');
const avgScore = scores.length > 0 ? scores.reduce((a, b) => a + b, 0) / scores.length : 5;

// Capture review feedback as spare text
const spareText = [...(projectState.spareText || [])];
spareText.push({
  source: 'Review Feedback',
  chapter: projectState.currentChapterDraft.chapterNumber,
  type: 'developmental_review',
  content: JSON.stringify(developmentalFeedback, null, 2).substring(0, 5000)
});
if (lineEditFeedback.lineEdits) {
  spareText.push({
    source: 'Claude: Line Editing',
    chapter: projectState.currentChapterDraft.chapterNumber,
    type: 'line_edit_suggestions',
    content: JSON.stringify(lineEditFeedback.lineEdits, null, 2).substring(0, 5000)
  });
}

// Logging
const log = [...(projectState.pipelineLog || [])];
log.push({
  timestamp: new Date().toISOString(),
  node: 'Aggregate Review Feedback',
  chapter: projectState.currentChapterDraft.chapterNumber,
  action: 'Reviews aggregated',
  avgScore: avgScore.toFixed(1),
  needsRevision: avgScore < 7,
  tokens: newTokens.reduce((sum, t) => sum + t.inputTokens + t.outputTokens, 0)
});

return {
  json: {
    ...projectState,
    tokenUsage,
    pipelineLog: log,
    spareText,
    review: {
      developmental: developmentalFeedback,
      consistency: consistencyFeedback,
      lineEdit: lineEditFeedback,
      averageScore: avgScore.toFixed(1),
      needsRevision: avgScore < 7,
      reviewedAt: new Date().toISOString()
    }
  }
};

