${(() => { const ch = String($json.currentChapterDraft?.chapterNumber || $json.currentChapter); const outlines = (() => { try { return typeof $json.chapterOutlines === 'string' ? JSON.parse($json.chapterOutlines) : ($json.chapterOutlines || {}); } catch(e) { return {}; } })(); return outlines[ch] ? 'This chapter should follow this outline: ' + outlines[ch] : 'No specific outline — maintain narrative continuity.'; })()}

