function extractTokenUsage(response, node, model, provider, inputPricePerM, outputPricePerM) {
  let inputTokens = 0, outputTokens = 0;
  if (provider === 'google') {
    inputTokens = response.usageMetadata?.promptTokenCount || 0;
    outputTokens = response.usageMetadata?.candidatesTokenCount || 0;
  } else if (provider === 'anthropic') {
    inputTokens = response.usage?.input_tokens || 0;
    outputTokens = response.usage?.output_tokens || 0;
  } else {
    inputTokens = response.usage?.prompt_tokens || 0;
    outputTokens = response.usage?.completion_tokens || 0;
  }
  const costUSD = (inputTokens * inputPricePerM / 1000000) + (outputTokens * outputPricePerM / 1000000);
  return { node, model, provider, inputTokens, outputTokens, costUSD: Math.round(costUSD * 1000000) / 1000000 };
}

// Update chapter with revision
const projectState = $('Aggregate Review Feedback').item.json;
const revision = $('Claude: Apply Revisions').item.json;

const newTokens = [
  extractTokenUsage(revision, 'Claude: Apply Revisions', 'claude-opus-4-6', 'anthropic', 15, 75)
];
const tokenUsage = [...(projectState.tokenUsage || []), ...newTokens];

let revisedText = '';
if (revision.content && revision.content[0]) {
  revisedText = revision.content[0].text;
}

// Capture original draft as spare text before replacing
const spareText = [...(projectState.spareText || [])];
spareText.push({
  source: 'Claude: Write Chapter Draft (pre-revision)',
  chapter: projectState.currentChapterDraft.chapterNumber,
  type: 'original_draft',
  content: projectState.currentChapterDraft.text.substring(0, 10000)
});

const revisionCount = (projectState.currentChapterDraft.revisionCount || 0) + 1;

// Logging
const log = [...(projectState.pipelineLog || [])];
log.push({
  timestamp: new Date().toISOString(),
  node: 'Update Chapter Draft',
  chapter: projectState.currentChapterDraft.chapterNumber,
  action: 'Revision applied (revision #' + revisionCount + ')',
  originalWords: projectState.currentChapterDraft.wordCount,
  revisedWords: revisedText.split(/\s+/).length,
  tokens: newTokens.reduce((sum, t) => sum + t.inputTokens + t.outputTokens, 0)
});

return {
  json: {
    ...projectState,
    tokenUsage,
    pipelineLog: log,
    spareText,
    currentChapterDraft: {
      ...projectState.currentChapterDraft,
      text: revisedText,
      wordCount: revisedText.split(/\s+/).length,
      revisionCount: revisionCount,
      lastRevisedAt: new Date().toISOString()
    },
    review: {
      ...projectState.review,
      needsRevision: false
    }
  }
};

// Finalize the current chapter and generate summary for continuity
const projectState = $('Aggregate Review Feedback').item.json;

// Store completed chapter
const chapters = projectState.completedChapters || [];
const chapterText = projectState.currentChapterDraft.text;

chapters.push({
  number: parseInt(projectState.currentChapter),
  text: chapterText,
  wordCount: projectState.currentChapterDraft.wordCount,
  finalScore: projectState.review.averageScore,
  completedAt: new Date().toISOString()
});

// Generate chapter summary for next-chapter continuity
const chapterSummaries = projectState.chapterSummaries || [];
const opening = chapterText.substring(0, 600);
const closing = chapterText.substring(Math.max(0, chapterText.length - 400));

// Extract plot/character info from reviews
const devReview = projectState.review?.developmental || {};
const plotInfo = typeof devReview.plot === 'string' ? devReview.plot : JSON.stringify(devReview.plot || '').substring(0, 400);
const characterInfo = typeof devReview.character === 'string' ? devReview.character : JSON.stringify(devReview.character || '').substring(0, 300);

chapterSummaries.push({
  number: parseInt(projectState.currentChapter),
  wordCount: projectState.currentChapterDraft.wordCount,
  opening: opening,
  closing: closing,
  plotEvents: plotInfo,
  characterState: characterInfo,
  score: projectState.review.averageScore
});

const currentChapter = parseInt(projectState.currentChapter);
const targetChapters = parseInt(projectState.targetChapters);

// Pipeline logging
const log = projectState.pipelineLog || [];
log.push({
  timestamp: new Date().toISOString(),
  node: 'Finalize Chapter',
  chapter: currentChapter,
  action: 'Chapter finalized',
  wordCount: projectState.currentChapterDraft.wordCount,
  score: projectState.review.averageScore,
  revisions: projectState.currentChapterDraft.revisionCount || 0
});

return {
  json: {
    ...projectState,
    completedChapters: chapters,
    chapterSummaries,
    pipelineLog: log,
    currentChapter: (currentChapter + 1).toString(),
    status: currentChapter >= targetChapters ? 'complete' : 'drafting'
  }
};

// Compile all chapters into final manuscript
const projectState = $('Finalize Chapter').item.json;
const chapters = projectState.completedChapters || [];

let manuscript = `# ${projectState.concept.substring(0, 100)}\n`;
manuscript += `## A ${projectState.genre} Novel\n\n`;
manuscript += `---\n\n`;

for (const chapter of chapters.sort((a, b) => a.number - b.number)) {
  manuscript += `# Chapter ${chapter.number}\n\n`;
  manuscript += chapter.text;
  manuscript += `\n\n---\n\n`;
}

const totalWords = chapters.reduce((sum, ch) => sum + ch.wordCount, 0);
const avgScore = chapters.reduce((sum, ch) => sum + parseFloat(ch.finalScore), 0) / chapters.length;

// Cost summary
const tokenUsage = projectState.tokenUsage || [];
const byModel = {};
for (const entry of tokenUsage) {
  if (!byModel[entry.model]) {
    byModel[entry.model] = { provider: entry.provider, calls: 0, inputTokens: 0, outputTokens: 0, costUSD: 0 };
  }
  byModel[entry.model].calls++;
  byModel[entry.model].inputTokens += entry.inputTokens;
  byModel[entry.model].outputTokens += entry.outputTokens;
  byModel[entry.model].costUSD += entry.costUSD;
}
for (const model of Object.keys(byModel)) {
  byModel[model].costUSD = Math.round(byModel[model].costUSD * 1000000) / 1000000;
}
const totalCostUSD = Math.round(tokenUsage.reduce((sum, e) => sum + e.costUSD, 0) * 100) / 100;

// Final log entry
const log = [...(projectState.pipelineLog || [])];
log.push({
  timestamp: new Date().toISOString(),
  node: 'Compile Full Manuscript',
  action: 'Manuscript compiled',
  totalChapters: chapters.length,
  totalWords,
  avgScore: avgScore.toFixed(1),
  totalCostUSD
});

return {
  json: {
    ...projectState,
    manuscript,
    summary: {
      totalChapters: chapters.length,
      totalWords,
      averageScore: avgScore.toFixed(1),
      completedAt: new Date().toISOString()
    },
    costSummary: {
      totalCostUSD,
      totalApiCalls: tokenUsage.length,
      byModel,
      breakdown: tokenUsage
    },
    pipelineLog: log,
    spareText: projectState.spareText || []
  }
};
